[CmdletBinding()]
param([string]$PackageRoot=(Join-Path (Resolve-Path (Join-Path $PSScriptRoot '../..')).Path 'artifacts/http2-websocket-packages'),[string]$ArtifactRoot=(Join-Path (Resolve-Path (Join-Path $PSScriptRoot '../..')).Path 'artifacts/http2-websocket-extracted-smoke'))
$ErrorActionPreference='Stop';$PackageRoot=[IO.Path]::GetFullPath($PackageRoot);$ArtifactRoot=[IO.Path]::GetFullPath($ArtifactRoot);$repoRoot=(Resolve-Path (Join-Path $PSScriptRoot '../..')).Path;if(-not$ArtifactRoot.StartsWith([IO.Path]::GetFullPath((Join-Path $repoRoot 'artifacts')),[StringComparison]::OrdinalIgnoreCase)){throw 'Smoke artifacts must remain under this worktree artifacts directory.'}
function Resolve-One([string]$pattern){$matches=@(Get-ChildItem -LiteralPath $PackageRoot -Filter $pattern -File);if($matches.Count-ne 1){throw "Expected one $pattern package, observed $($matches.Count)."};$matches[0].FullName}
function Expand-One([string]$archive,[string]$destination){New-Item -ItemType Directory -Force $destination|Out-Null;[IO.Compression.ZipFile]::ExtractToDirectory($archive,$destination);$manifest=Get-Content (Join-Path $destination 'protocol-lab-package.json') -Raw|ConvertFrom-Json;if($manifest.schemaVersion-ne'protocol-lab-package-v2'){throw "$archive is not package-v2"};$manifest}
if(Test-Path $ArtifactRoot){Remove-Item -LiteralPath $ArtifactRoot -Recurse -Force};New-Item -ItemType Directory -Force $ArtifactRoot|Out-Null;$scenarioArchive=Resolve-One 'org.protocol-lab.components.scenario.http2-websocket-performance.0.1.1.plabpkg';$executorArchive=Resolve-One 'org.protocol-lab.components.executor.go-http2-websocket-executor.0.1.0.win-x64.plabpkg';$targetArchive=Resolve-One 'org.protocol-lab.components.implementation.kestrel-http2-websocket.0.1.0.win-x64.plabpkg';$scenarioRoot=Join-Path $ArtifactRoot scenario;$executorRoot=Join-Path $ArtifactRoot executor;$targetRoot=Join-Path $ArtifactRoot target;$scenarioManifest=Expand-One $scenarioArchive $scenarioRoot;$executorManifest=Expand-One $executorArchive $executorRoot;$targetManifest=Expand-One $targetArchive $targetRoot;$authority=Get-Content (Join-Path $scenarioRoot 'authority-lock.json') -Raw|ConvertFrom-Json;if($authority.commit-ne'8c4bbe8b7ee94b0e53427dd5ac15e7ede7b77574'){throw 'authority commit mismatch'};if($scenarioManifest.providedScenarios.Count-ne 6-or$executorManifest.providedTestExecutors[0].scenarios.Count-ne 6-or$targetManifest.providedImplementations[0].scenarios.Count-ne 6){throw 'six-ID package claim mismatch'};if((@($scenarioManifest.providedLoadProfiles.loadProfileId)-join ',')-ne'websocket-smoke,websocket-comparison,diagnostic'){throw 'scenario load-profile claim mismatch'};foreach($license in @('golang-x-net-LICENSE.txt','golang-x-text-LICENSE.txt')){if(-not(Test-Path (Join-Path $executorRoot "third-party/$license"))){throw "missing $license"}};foreach($notice in @('LICENSE.txt','ThirdPartyNotices.txt')){if(-not(Test-Path (Join-Path $targetRoot "third-party/$notice"))){throw "missing $notice"}}
$names=@('PLAB_LISTEN_ADDRESS','PLAB_SCENARIO_ID','PLAB_TLS_CERTIFICATE_PATH','PLAB_TLS_PRIVATE_KEY_PATH','PLAB_TARGET_BASE_URL','PLAB_ARTIFACT_DIR','PLAB_TLS_ROOT_CERTIFICATE_PATH','PLAB_EXECUTOR_ID','PLAB_EXECUTOR_VERSION','PLAB_LOAD_GENERATOR_ID','PLAB_LOAD_GENERATOR_VERSION','PLAB_PROTOCOL','PLAB_PROTOCOL_VARIANT','PLAB_LOAD_PROFILE_ID');$saved=@{};foreach($name in $names){$saved[$name]=[Environment]::GetEnvironmentVariable($name,'Process')};$target=$null
try{$env:PLAB_LISTEN_ADDRESS='127.0.0.1:18451';$env:PLAB_SCENARIO_ID='http2.websocket.rfc8441.extended-connect';$env:PLAB_TLS_CERTIFICATE_PATH=Join-Path $targetRoot 'certs/leaf.pem';$env:PLAB_TLS_PRIVATE_KEY_PATH=Join-Path $targetRoot 'certs/leaf-key.pem';$targetOut=Join-Path $ArtifactRoot 'target.stdout.log';$targetErr=Join-Path $ArtifactRoot 'target.stderr.log';$target=Start-Process (Join-Path $targetRoot 'bin/win-x64/KestrelHttp2WebSocket.exe') -RedirectStandardOutput $targetOut -RedirectStandardError $targetErr -WindowStyle Hidden -PassThru;$ready=$false;for($i=0;$i-lt100;$i++){if((Test-Path $targetOut)-and((Get-Content $targetOut -Raw)-match'"eventName":"ready"')){$ready=$true;break};Start-Sleep -Milliseconds 100};if(-not$ready){throw "target not ready: $(Get-Content $targetErr -Raw)"};$targetReady=((Get-Content $targetOut)|Where-Object{$_-like'*"eventName":"ready"*'}|Select-Object -First 1)|ConvertFrom-Json;if($targetReady.protocolVersion-ne'HTTP/2'-or$targetReady.settingsEnableConnectProtocol-ne 1-or$targetReady.alpn-ne'h2'-or$targetReady.certificateDerSha256-ne'fe996190f39355e3cfc201cbb7e2cba962a701b94ed08ff49e68e830216d0109'){throw 'target readiness mismatch'}
$env:PLAB_TARGET_BASE_URL='https://127.0.0.1:18451';$env:PLAB_TLS_ROOT_CERTIFICATE_PATH=Join-Path $executorRoot 'certs/root.pem';$env:PLAB_EXECUTOR_ID='go-http2-websocket-executor';$env:PLAB_EXECUTOR_VERSION='0.1.0';$env:PLAB_LOAD_GENERATOR_ID='go-x-net-http2-websocket-load';$env:PLAB_LOAD_GENERATOR_VERSION='0.1.0';$env:PLAB_PROTOCOL='h2';$env:PLAB_PROTOCOL_VARIANT='websocket-h2-extended-connect';$binary=Join-Path $executorRoot 'bin/win-x64/go-http2-websocket-executor.exe';$ids=@('http2.websocket.rfc8441.extended-connect','http2.websocket.rfc8441.control-frames','http2.websocket.rfc8441.text-echo','http2.websocket.rfc8441.binary-echo','http2.websocket.rfc8441.close','http2.websocket.rfc8441.multi-message-text-echo');$outcomes=@();foreach($id in $ids){$profile=if($id-like'*.multi-message-*'){'diagnostic'}else{'websocket-smoke'};$env:PLAB_LOAD_PROFILE_ID=$profile;$dir=Join-Path $ArtifactRoot ($id-replace'\.','-');New-Item -ItemType Directory -Force $dir|Out-Null;$env:PLAB_SCENARIO_ID=$id;$env:PLAB_ARTIFACT_DIR=$dir;$run=Start-Process $binary -ArgumentList '--validation-only' -RedirectStandardOutput (Join-Path $dir 'load.stdout.log') -RedirectStandardError (Join-Path $dir 'load.stderr.log') -WindowStyle Hidden -Wait -PassThru;if($run.ExitCode-ne 0){throw "$id failed: $(Get-Content (Join-Path $dir 'load.stderr.log') -Raw)"};foreach($required in @('validation.json','protocol-proof.json','websocket-summary.json','payload-hash.json','http2-frame-summary.json','frame-summary.json','result.json','http2-websocket-executor-result.json','websocket-load-summary.json','executor-identity.json','load-generator-identity.json','load.stdout.log','load.stderr.log')){if(-not(Test-Path (Join-Path $dir $required))){throw "$id missing $required"}};$result=Get-Content (Join-Path $dir 'result.json') -Raw|ConvertFrom-Json;$proof=$result.protocolProof;if($proof.tlsVersion-ne'TLS 1.3'-or$proof.alpn-ne'h2'-or$proof.settingsEnableConnectProtocol-ne 1-or$proof.requestPseudoHeaders.':method'-ne'CONNECT'-or$proof.requestPseudoHeaders.':protocol'-ne'websocket'-or$proof.requestPseudoHeaders.':scheme'-ne'https'-or$proof.requestPseudoHeaders.':authority'-ne'websocket.plab.test'-or$proof.requestPseudoHeaders.':path'-ne'/websocket'-or$proof.responseStatus-ne 200-or$proof.secWebSocketAcceptPresent-or$proof.secWebSocketKeyPresent-or$proof.prohibitedRequestHeadersPresent-or-not$proof.clientMaskObserved-or$proof.closeSent-ne 1000-or$proof.closeReceived-ne 1000-or-not$proof.cleanCompletion){throw "$id common proof failed"};if($id-like'*.multi-message-*' -and($proof.messageCount-ne 100-or-not$proof.strictOrdering)){throw 'multi-message ordering proof failed'};if($id-like'*.control-frames' -and(-not$proof.pingSent-or-not$proof.pongReceived)){throw 'ping/pong proof failed'};if($id-like'*.text-echo' -and$proof.payloadSha256-ne'504585b0bb4fd77012ea2575efbcdb58f4c33e6b543e9567a65896d213720c29'){throw 'text hash failed'};if($id-like'*.binary-echo' -and($proof.messageBytes-ne 1024-or$proof.payloadSha256-ne'9b6ce55f379e9771551de6939556a7e6b949814ae27c2f5cfd5dbeb378ce7c2a')){throw 'binary hash failed'};if($result.metrics.completedOperations-ne 1-or$result.metrics.failedOperations-ne 0-or$result.metrics.timedOutOperations-ne 0){throw "$id outcomes failed"};$outcomes+=[pscustomobject]@{scenarioId=$id;loadProfileId=$profile;completed=1;failed=0;timedOut=0;messageCount=$proof.messageCount}}
$unsupported=@('http1.websocket.rfc6455.cleartext.upgrade','http1.websocket.rfc6455.cleartext.control-frames','http1.websocket.rfc6455.cleartext.text-echo','http1.websocket.rfc6455.cleartext.binary-echo','http1.websocket.rfc6455.cleartext.close','http1.websocket.rfc6455.tls.upgrade','http1.websocket.rfc6455.tls.control-frames','http1.websocket.rfc6455.tls.text-echo','http1.websocket.rfc6455.tls.binary-echo','http1.websocket.rfc6455.tls.close','http1.websocket.rfc6455.tls.subprotocol-text-echo','http1.websocket.rfc6455.tls.permessage-deflate-binary-echo','http3.websocket.rfc9220.extended-connect','http3.websocket.rfc9220.control-frames','http3.websocket.rfc9220.text-echo','http3.websocket.rfc9220.binary-echo','http3.websocket.rfc9220.close','http3.websocket.rfc9220.fragmented-binary-echo');foreach($id in $unsupported){$dir=Join-Path $ArtifactRoot ('unsupported-'+($id-replace'\.','-'));New-Item -ItemType Directory -Force $dir|Out-Null;$env:PLAB_SCENARIO_ID=$id;$env:PLAB_ARTIFACT_DIR=$dir;$run=Start-Process $binary -RedirectStandardOutput (Join-Path $dir 'load.stdout.log') -RedirectStandardError (Join-Path $dir 'load.stderr.log') -WindowStyle Hidden -Wait -PassThru;if($run.ExitCode-ne 3){throw "$id did not fail unsupported"}};$unknown=Join-Path $ArtifactRoot unknown;New-Item -ItemType Directory -Force $unknown|Out-Null;$env:PLAB_SCENARIO_ID='http2.websocket.unknown';$env:PLAB_ARTIFACT_DIR=$unknown;$run=Start-Process $binary -RedirectStandardOutput (Join-Path $unknown 'load.stdout.log') -RedirectStandardError (Join-Path $unknown 'load.stderr.log') -WindowStyle Hidden -Wait -PassThru;if($run.ExitCode-ne 2){throw 'unknown ID did not fail closed'};$targetProof=Get-Content $targetOut -Raw;if(([regex]::Matches($targetProof,'\"eventName\":\"websocket-clean-close\"')).Count-lt 6-or([regex]::Matches($targetProof,'\"clientMaskObserved\":true')).Count-lt 6){throw 'target raw-frame masking/close proof incomplete'};[pscustomobject]@{authorityCommit=$authority.commit;scenarioPackageSha256=(Get-FileHash $scenarioArchive -Algorithm SHA256).Hash.ToLowerInvariant();executorPackageSha256=(Get-FileHash $executorArchive -Algorithm SHA256).Hash.ToLowerInvariant();targetPackageSha256=(Get-FileHash $targetArchive -Algorithm SHA256).Hash.ToLowerInvariant();outcomes=$outcomes;unsupportedCount=$unsupported.Count;evidenceRoot=$ArtifactRoot}|ConvertTo-Json -Depth 8
}finally{if($null-ne$target-and-not$target.HasExited){Stop-Process -Id $target.Id -Force};foreach($name in $names){[Environment]::SetEnvironmentVariable($name,$saved[$name],'Process')}}
